pload.s3.us-east-2.amazonaws.com/china-x-india-military-clash-by-december-31-eggJM4CWN6Un.jpg", "ready": false, "active": true, "closed": true, "funded": false, "spread": 0.001, "volume": "73185.754279", "bestAsk": 0.001, "endDate": "2025-12-31T12:00:00Z", "feeType": null, "negRisk": false, "umaBond": "500", "approved": true, "archived": false, "featured": false, "outcomes": "[\\"Yes\\", \\"No\\"]", "question": "China x India military clash by December 31?", "createdAt": "2025-01-30T19:15:12.055523Z", "deploying": false, "startDate": "2025-01-30T21:29:11.808Z", "umaReward": "5", "updatedAt": "2026-02-06T20:53:31.771465Z", "volume1mo": 8221.565354, "volume1wk": 1986.7765, "volume1yr": 73185.75427899958, "volumeNum": 73185.754279, "closedTime": "2026-01-01 09:34:37+00", "endDateIso": "2025-12-31", "questionID": "0x21a57e5bd440a2fa423cdaeffd795ec4dc3a6a7ed297f9fc630f59fcbabfd1fd", "resolvedBy": "0x6A9D222616C90FcA5754cd1333cFD9b7fb6a4F74", "restricted": true, "rfqEnabled": false, "umaEndDate": "2026-01-01T09:34:37Z", "volumeClob": 73185.754279, "conditionId": "0x689a77ca28cf59efae262fd37d07aa787194d52b13bbe009a223de15bf5c62af", "description": "This market will resolve to \\"Yes\\" if there is a military encounter between the military forces of China (People's Republic of China) and India between January 29, and December 31, 2025, 11:59 PM ET. Otherwise, this market will resolve to \\"No\\".\\n\\nA \\"military encounter\\" is defined as any incident involving the use of force such as missile strikes, artillery fire, exchange of gunfire, or other forms of direct military engagement between Chinese and Indian military forces. Hand-to-hand combat with the use of melee weapons between military personnel, will qualify. For example the 2020 Galwan Valley clash and the 2022 Yangtse clash would both count.\\n\\nNon-violent actions, such as warning shots, artillery fire into uninhabited areas, or missile launches that land in territorial waters or pass through airspace, will not qualify for a \\"Yes\\" resolution. Intentional ship ramming that results in significant damage to (e.g., a hole in the hull) or the sinking of a military ship by another will count toward a \\"Yes\\" resolution, however minor damage (scrapes, dents) will not.\\n\\nNote: the China Coast Guard (CCG) is part of the military, however the Indian Coast Guard (ICG) is not.\\n\\nThe resolution source for this market will be a consensus of credible reporting.", "feesEnabled": false, "seriesColor": "", "clobTokenIds": "[\\"62499647704758013801224496519154801919449219197687180369505612744147504118777\\", \\"89667254973027475163940771416019167537897714895546880163448338769528535684137\\"]", "negRiskOther": false, "orderMinSize": 5, "startDateIso": "2025-01-30", "submitted_by": "0x91430CaD2d3975766499717fA0D66A78D814E5c5", "gameStartTime": "2025-09-10 02:17:00+00", "outcomePrices": "[\\"0\\", \\"1\\"]", "showGmpSeries": false, "volume1moClob": 8221.565354, "volume1wkClob": 1986.7765, "volume1yrClob": 73185.75427899958, "customLiveness": 0, "groupItemTitle": "December 31", "lastTradePrice": 1, "rewardsMinSize": 100, "showGmpOutcome": false, "acceptingOrders": false, "enableOrderBook": true, "clearBookOnStart": true, "hasReviewedDates": true, "manualActivation": false, "resolutionSource": "", "rewardsMaxSpread": 3.5, "oneDayPriceChange": -0.0015, "pendingDeployment": false, "groupItemThreshold": "1", "marketMakerAddress": "", "oneWeekPriceChange": -0.003, "automaticallyActive": true, "oneMonthPriceChange": -0.0215, "requiresTranslation": false, "umaResolutionStatus": "resolved", "automaticallyResolved": true, "holdingRewardsEnabled": false, "orderPriceMinTickSize": 0.001, "umaResolutionStatuses": "[\\"proposed\\"]", "acceptingOrdersTimestamp": "2025-01-30T21:28:00Z", "pagerDutyNotificationEnabled": false}, {"id": "521028", "new": false, "cyom": false, "icon": "https://polymarket-upload.s3.us-east-2.amazonaws.com/china-x-india-military-clash-by-december-31-eggJM4CWN6Un.jpg", "slu